// ============================================================
// src/components/admin/BillingTab.js
// ============================================================
import React, { useState, useEffect, useCallback } from "react";
import api from "../../utils/api";

// ── same months array as PatientsTab ─────────────────────────
const MONTHS = ["January","February","March","April","May","June",
  "July","August","September","October","November","December"];

const DENTAL_TREATMENTS = [
  "General Checkup & Cleaning","Teeth Whitening","Dental Implant","Root Canal Therapy",
  "Crown / Cap","Bridge","Orthodontic Treatment (Braces)","Invisalign","Tooth Extraction",
  "Wisdom Tooth Removal","Composite Filling","Amalgam Filling","Dental X-Ray",
  "Scaling & Polishing","Gum Treatment (Periodontics)","Smile Makeover","Veneer",
  "Pediatric Dentistry","Fluoride Treatment","Mouthguard / Night Guard",
  "Consultation Fee","Follow-Up Visit","Oral Surgery","Jaw Treatment (TMJ)","Emergency Dental Care",
];

const PAYMENT_METHODS = [
  { value:"cash",      label:"Cash"      },
  { value:"upi",       label:"UPI"       },
  { value:"card",      label:"Card"      },
  { value:"insurance", label:"Insurance" },
  { value:"other",     label:"Other"     },
];

const STATUS_CFG = {
  paid:    { label:"Paid",    color:"#16a34a", bg:"#f0fdf4" },
  partial: { label:"Partial", color:"#d97706", bg:"#fffbeb" },
  unpaid:  { label:"Unpaid",  color:"#dc2626", bg:"#fef2f2" },
};

// ── helpers ───────────────────────────────────────────────────
function fmtMoney(n) {
  return "Rs. " + Number(n||0).toLocaleString("en-IN",{minimumFractionDigits:2,maximumFractionDigits:2});
}
function todayISO() { return new Date().toISOString().split("T")[0]; }
function friendlyDate(d) {
  if (!d) return "--";
  const dt = new Date(d+"T00:00:00");
  if (isNaN(dt.getTime())) return d;
  return dt.getDate()+" "+MONTHS[dt.getMonth()]+" "+dt.getFullYear();
}
function calcTotals(items, discountType, discountValue, gstPercent) {
  const sub  = items.reduce((s,i)=>s+(parseFloat(i.amount)||0),0);
  const disc = discountType==="percent"
    ? (sub*(parseFloat(discountValue)||0))/100
    : (parseFloat(discountValue)||0);
  const after = Math.max(0, sub-disc);
  const gst   = (after*(parseFloat(gstPercent)||0))/100;
  return { subtotal:sub, discountAmount:disc, gstAmount:gst, totalAmount:after+gst };
}

// ── shared styles ─────────────────────────────────────────────
const CARD  = { background:"#fff", border:"1px solid #e5e7eb", borderRadius:"10px", padding:"18px 20px", boxShadow:"0 1px 4px rgba(0,0,0,0.06)" };
const LABEL = { fontSize:"11px", color:"#94a3b8", fontWeight:600, textTransform:"uppercase", display:"block", marginBottom:"4px" };
const INPUT = { width:"100%", padding:"8px 10px", borderRadius:"7px", border:"1px solid #d1d5db", fontSize:"13px", outline:"none", boxSizing:"border-box" };
const BTN   = { padding:"9px 20px", borderRadius:"8px", background:"#1e40af", color:"#fff", border:"none", fontSize:"13px", fontWeight:700, cursor:"pointer" };
const GHOST = { padding:"8px 16px", borderRadius:"8px", background:"#f1f5f9", color:"#374151", border:"1px solid #d1d5db", fontSize:"13px", fontWeight:600, cursor:"pointer" };

// ── jsPDF loader — EXACT same as PatientsTab ─────────────────
function generatePDF(buildFn) {
  if (window.jspdf) { buildFn(); return; }
  const existing = document.getElementById("jspdf-cdn");
  if (existing) { existing.addEventListener("load", buildFn); return; }
  const script = document.createElement("script");
  script.id = "jspdf-cdn";
  script.src = "https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js";
  script.crossOrigin = "anonymous";
  script.onload = buildFn;
  script.onerror = () => {};
  document.head.appendChild(script);
}

// ── InvoiceShareModal — same pattern as PrescriptionModal ─────
function InvoiceShareModal({ inv, onClose, showNotify }) {
  const [pdfUrl,         setPdfUrl]         = useState("");
  const [loading,        setLoading]        = useState(true);
  const [pdfBlob,        setPdfBlob]        = useState(null);
  const [fileName,       setFileName]       = useState("");
  const [canNativeShare, setCanNativeShare] = useState(false);

  // close on Escape — same as PrescriptionModal
  useEffect(() => {
    const handler = (e) => { if (e.key==="Escape") onClose(); };
    document.addEventListener("keydown", handler);
    return () => document.removeEventListener("keydown", handler);
  }, [onClose]);

  useEffect(() => {
    generatePDF(buildPDF);
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const buildPDF = () => {
    const { jsPDF } = window.jspdf;
    const pdf = new jsPDF({ unit:"mm", format:"a4", orientation:"portrait" });
    const W=210, H=297;

    // ── colour helpers — IDENTICAL to PrescriptionModal ──────
    const sf=(c)=>pdf.setFillColor(c[0],c[1],c[2]);
    const sd=(c)=>pdf.setDrawColor(c[0],c[1],c[2]);
    const st=(c)=>pdf.setTextColor(c[0],c[1],c[2]);

    // ── EXACT SAME PALETTE as PrescriptionModal ───────────────
    const NAVY=[8,25,65], BLUE=[20,80,160];
    const LBLUE=[210,228,248], LBLUE2=[232,242,252], MIDBLUE=[160,195,235];
    const TEAL=[0,130,130], TEAL2=[210,240,240];
    const WHITE=[255,255,255], LGRAY=[245,247,251], LGRAY2=[250,251,254], LGRAY3=[240,243,248];
    const GRAY=[115,118,130], GRAY2=[75,80,95];
    const GOLD=[170,130,40], GOLD2=[250,245,225];
    const GREEN=[22,163,74], RED=[185,28,28];

    const today    = new Date();
    const todayFmt = today.getDate()+" "+MONTHS[today.getMonth()]+" "+today.getFullYear();
    const invSerial= "PS-INV-"+today.getFullYear()+("0"+(today.getMonth()+1)).slice(-2)+("0"+today.getDate()).slice(-2)+"-"+Math.floor(1000+Math.random()*8999);

    // doc = same object structure as prescription
    const doc = { name: inv.doctorName || "Doctor", qual:"", reg:"" };

    // ── Outer border — IDENTICAL ──────────────────────────────
    sd(MIDBLUE); pdf.setLineWidth(0.8); pdf.rect(3.5,3.5,W-7,H-7,"S");
    sd(LBLUE);   pdf.setLineWidth(0.3); pdf.rect(5.5,5.5,W-11,H-11,"S");

    // ── Header — IDENTICAL layout to PrescriptionModal ────────
    sf(NAVY); pdf.rect(3.5,3.5,W-7,46,"F");
    sf(BLUE); pdf.rect(3.5,43,W-7,10,"F");
    sf(LBLUE);pdf.rect(3.5,53,W-7,6,"F");

    // left side: doctor name (same position as prescription)
    st(WHITE); pdf.setFontSize(18); pdf.setFont("helvetica","bold");
    pdf.text(doc.name, 14, 19);
    st(LBLUE); pdf.setFontSize(8); pdf.setFont("helvetica","normal");
    pdf.text((doc.qual||"").toUpperCase(), 14, 26);
    sd(MIDBLUE); pdf.setLineWidth(0.25); pdf.line(14,28.5,W-40,28.5);
    st(LGRAY); pdf.setFontSize(7);
    pdf.text("Reg. No.:  "+(doc.reg||"—"), 14, 33.5);
    pdf.text("Specialisation:  Dental & Oral Health Care", 14, 38.5);

    // right side: hospital name (same position)
    st(WHITE); pdf.setFontSize(15); pdf.setFont("helvetica","bold");
    pdf.text("PEARLSMILE", W-10, 19, { align:"right" });
    st(LBLUE); pdf.setFontSize(7.5); pdf.setFont("helvetica","normal");
    pdf.text("DENTAL HOSPITAL", W-10, 25.5, { align:"right" });
    sd(MIDBLUE); pdf.setLineWidth(0.25); pdf.line(W-72,28.5,W-10,28.5);
    st(LGRAY); pdf.setFontSize(6.8);
    pdf.text("12, Dental Plaza, MG Road, Pune - 411001", W-10, 33.5, { align:"right" });
    pdf.text("+91 87936 08083  |  care@pearlsmiledental.in", W-10, 38.5, { align:"right" });

    // centre bar — "TAX INVOICE" instead of "DIGITAL PRESCRIPTION"
    st(WHITE); pdf.setFontSize(9); pdf.setFont("helvetica","bold");
    pdf.text("TAX INVOICE", W/2, 50, { align:"center" });
    st(LBLUE2); pdf.setFontSize(7); pdf.setFont("helvetica","normal");
    pdf.text("Invoice No.: "+(inv.invoiceNumber||"—"), 10, 50);
    pdf.text("Date: "+friendlyDate(inv.invoiceDate), W-10, 50, { align:"right" });

    st(BLUE); pdf.setFontSize(7.5); pdf.setFont("helvetica","bold");
    pdf.text("PATIENT INFORMATION", W/2, 57, { align:"center" });

    // ── Patient info table — IDENTICAL drawCell to prescription
    const infoTop=61;
    sf(LGRAY3); pdf.rect(10,infoTop,W-20,33,"F");
    sd(LBLUE); pdf.setLineWidth(0.25); pdf.rect(10,infoTop,W-20,33,"S");
    sd(MIDBLUE); pdf.setLineWidth(0.2);
    pdf.line(W/2,infoTop,W/2,infoTop+33);
    let rdy2=infoTop+11;
    for(let ri=0;ri<2;ri++){ pdf.line(10,rdy2,W-10,rdy2); rdy2+=11; }

    const drawCell=(label,value,x,y,maxW)=>{
      st(GRAY2); pdf.setFont("helvetica","bold"); pdf.setFontSize(6.8);
      pdf.text(label, x+3, y+4);
      st(NAVY); pdf.setFont("helvetica","normal"); pdf.setFontSize(8.5);
      const val=pdf.splitTextToSize(String(value||"—"),maxW||75);
      pdf.text(val[0], x+3, y+9.5);
    };
    const cHalf=W/2;
    drawCell("PATIENT NAME",  inv.patientName||"—",                                        10,    infoTop,    cHalf-16);
    drawCell("MOBILE",        inv.patientPhone||"—",                                       cHalf, infoTop,    cHalf-16);
    drawCell("AGE / GENDER",  (inv.patientAge||"—")+(inv.patientGender?" | "+inv.patientGender:""), 10, infoTop+11, cHalf-16);
    drawCell("INVOICE DATE",  friendlyDate(inv.invoiceDate),                               cHalf, infoTop+11, cHalf-16);
    drawCell("DOCTOR",        doc.name,                                                    10,    infoTop+22, cHalf-16);
    drawCell("PAYMENT STATUS",(inv.paymentStatus||"unpaid").toUpperCase()+" | "+(inv.paymentMethod||"—").toUpperCase(), cHalf, infoTop+22, cHalf-16);

    // ── Treatments table ──────────────────────────────────────
    const tblTop=infoTop+39;
    sf(BLUE); pdf.rect(10,tblTop,W-20,8,"F");
    st(WHITE); pdf.setFont("helvetica","bold"); pdf.setFontSize(7.5);
    pdf.text("TREATMENT / SERVICE",       14,   tblTop+5.5);
    pdf.text("QTY",                        122,  tblTop+5.5, { align:"center" });
    pdf.text("RATE (Rs.)",                 148,  tblTop+5.5, { align:"right" });
    pdf.text("AMOUNT (Rs.)",               W-12, tblTop+5.5, { align:"right" });

    let rowY=tblTop+8;
    (inv.items||[]).forEach((item,idx)=>{
      const bg=idx%2===0?LGRAY2:WHITE;
      sf(bg); pdf.rect(10,rowY,W-20,9,"F");
      sd(LBLUE); pdf.setLineWidth(0.15); pdf.rect(10,rowY,W-20,9,"S");
      st(NAVY); pdf.setFont("helvetica","normal"); pdf.setFontSize(8);
      const tname=pdf.splitTextToSize(item.treatment||"",92);
      pdf.text(tname[0],14,rowY+6);
      pdf.text(String(item.quantity||1),122,rowY+6,{align:"center"});
      pdf.text(Number(item.rate  ||0).toLocaleString("en-IN",{minimumFractionDigits:2}),148,rowY+6,{align:"right"});
      pdf.text(Number(item.amount||0).toLocaleString("en-IN",{minimumFractionDigits:2}),W-12,rowY+6,{align:"right"});
      rowY+=9;
    });
    rowY+=3;

    // ── Totals block ──────────────────────────────────────────
    const totX=W/2;
    // subtotal row
    sf(LGRAY3); pdf.rect(totX,rowY,W-10-totX,8,"F");
    sd(LBLUE); pdf.setLineWidth(0.15); pdf.rect(totX,rowY,W-10-totX,8,"S");
    st(GRAY2); pdf.setFont("helvetica","normal"); pdf.setFontSize(8);
    pdf.text("Subtotal",totX+4,rowY+5.5);
    pdf.text("Rs. "+Number(inv.subtotal||0).toLocaleString("en-IN",{minimumFractionDigits:2}),W-12,rowY+5.5,{align:"right"});
    rowY+=8;
    // discount
    if((inv.discountAmount||0)>0){
      sf(LGRAY3); pdf.rect(totX,rowY,W-10-totX,8,"F");
      sd(LBLUE); pdf.setLineWidth(0.15); pdf.rect(totX,rowY,W-10-totX,8,"S");
      st(RED); pdf.setFont("helvetica","normal"); pdf.setFontSize(8);
      pdf.text("Discount ("+(inv.discountType==="percent"?(inv.discountValue||0)+"%":"Flat")+")",totX+4,rowY+5.5);
      pdf.text("- Rs. "+Number(inv.discountAmount).toLocaleString("en-IN",{minimumFractionDigits:2}),W-12,rowY+5.5,{align:"right"});
      rowY+=8;
    }
    // gst
    if((inv.gstAmount||0)>0){
      sf(LGRAY3); pdf.rect(totX,rowY,W-10-totX,8,"F");
      sd(LBLUE); pdf.setLineWidth(0.15); pdf.rect(totX,rowY,W-10-totX,8,"S");
      st(TEAL); pdf.setFont("helvetica","normal"); pdf.setFontSize(8);
      pdf.text("GST ("+(inv.gstPercent||0)+"%)",totX+4,rowY+5.5);
      pdf.text("+ Rs. "+Number(inv.gstAmount).toLocaleString("en-IN",{minimumFractionDigits:2}),W-12,rowY+5.5,{align:"right"});
      rowY+=8;
    }
    // grand total — navy background like prescription header
    sf(NAVY); pdf.rect(totX,rowY,W-10-totX,10,"F");
    st(WHITE); pdf.setFont("helvetica","bold"); pdf.setFontSize(10);
    pdf.text("TOTAL AMOUNT",totX+4,rowY+7);
    pdf.text("Rs. "+Number(inv.totalAmount||0).toLocaleString("en-IN",{minimumFractionDigits:2}),W-12,rowY+7,{align:"right"});
    rowY+=10;
    // paid
    sf(LGRAY3); pdf.rect(totX,rowY,W-10-totX,8,"F");
    sd(LBLUE); pdf.setLineWidth(0.15); pdf.rect(totX,rowY,W-10-totX,8,"S");
    st(GREEN); pdf.setFont("helvetica","bold"); pdf.setFontSize(8.5);
    pdf.text("Amount Paid",totX+4,rowY+5.5);
    pdf.text("Rs. "+Number(inv.amountPaid||0).toLocaleString("en-IN",{minimumFractionDigits:2}),W-12,rowY+5.5,{align:"right"});
    rowY+=8;
    // due
    if((inv.amountDue||0)>0){
      sf(GOLD2); pdf.rect(totX,rowY,W-10-totX,8,"F");
      sd(LBLUE); pdf.setLineWidth(0.15); pdf.rect(totX,rowY,W-10-totX,8,"S");
      st(RED); pdf.setFont("helvetica","bold"); pdf.setFontSize(8.5);
      pdf.text("Amount Due",totX+4,rowY+5.5);
      pdf.text("Rs. "+Number(inv.amountDue).toLocaleString("en-IN",{minimumFractionDigits:2}),W-12,rowY+5.5,{align:"right"});
      rowY+=8;
    }
    rowY+=6;

    // ── Payment info box — same teal style as "next appointment" box in prescription
    sf(TEAL2); pdf.roundedRect(10,rowY,W-20,13,2,2,"F");
    sd(TEAL);  pdf.setLineWidth(0.4); pdf.roundedRect(10,rowY,W-20,13,2,2,"S");
    sf(TEAL);  pdf.roundedRect(10,rowY,10,13,2,2,"F");
    st(WHITE); pdf.setFont("helvetica","bold"); pdf.setFontSize(6.5);
    pdf.text("PAY",11.2,rowY+5.5); pdf.text("INFO",11.0,rowY+10);
    st(TEAL); pdf.setFont("helvetica","bold"); pdf.setFontSize(9);
    pdf.text("Payment Method:", 24, rowY+6.5);
    st(NAVY); pdf.setFontSize(10); pdf.setFont("helvetica","bold");
    pdf.text((inv.paymentMethod||"—").toUpperCase(), 68, rowY+6.5);
    st(GRAY); pdf.setFont("helvetica","normal"); pdf.setFontSize(7);
    const payRight=[];
    if(inv.receiptNumber) payRight.push("Receipt: "+inv.receiptNumber);
    if(inv.paymentDate)   payRight.push("Date: "+friendlyDate(inv.paymentDate));
    pdf.text(payRight.join("   "), W-12, rowY+11, { align:"right" });
    rowY+=19;

    // ── Insurance block (if applicable) — same gold style as "general advice"
    if(inv.insuranceProvider){
      sf(GOLD2); pdf.roundedRect(10,rowY,W-20,13,2,2,"F");
      sd(GOLD);  pdf.setLineWidth(0.35); pdf.roundedRect(10,rowY,W-20,13,2,2,"S");
      sf(GOLD);  pdf.roundedRect(10,rowY,10,13,2,2,"F");
      st(WHITE); pdf.setFont("helvetica","bold"); pdf.setFontSize(6.2);
      pdf.text("INS.",11.2,rowY+5.5); pdf.text("CLM.",11.0,rowY+10);
      st(GOLD); pdf.setFontSize(7.5); pdf.setFont("helvetica","bold");
      pdf.text("Insurance: "+inv.insuranceProvider, 24, rowY+6.5);
      st(GRAY2); pdf.setFont("helvetica","normal"); pdf.setFontSize(7);
      pdf.text("Claim No.: "+(inv.insuranceClaimNo||"—")+"   Status: "+(inv.insuranceStatus||"—").toUpperCase(), 24, rowY+11);
      rowY+=19;
    }

    // ── Notes (same gold advice box style) ────────────────────
    if(inv.notes){
      rowY+=4;
      sf(LGRAY2); pdf.roundedRect(10,rowY,W-20,14,2,2,"F");
      sd(LBLUE);  pdf.setLineWidth(0.25); pdf.roundedRect(10,rowY,W-20,14,2,2,"S");
      st(GRAY2); pdf.setFont("helvetica","bold"); pdf.setFontSize(7);
      pdf.text("Notes:", 14, rowY+6);
      st(NAVY); pdf.setFont("helvetica","normal"); pdf.setFontSize(7.5);
      const nl=pdf.splitTextToSize(inv.notes,W-38);
      pdf.text(nl[0]||"", 34, rowY+6);
      if(nl[1]) pdf.text(nl[1], 14, rowY+11.5);
      rowY+=18;
    }

    // ── Watermark — IDENTICAL to PrescriptionModal ────────────
    pdf.saveGraphicsState();
    pdf.setGState(new pdf.GState({ opacity:0.035 }));
    st(NAVY); pdf.setFont("helvetica","bold"); pdf.setFontSize(44);
    pdf.text("PEARLSMILE", W/2, H/2-5, { align:"center", angle:35 });
    pdf.restoreGraphicsState();

    // ── Doctor seal — COPY-PASTED EXACTLY from PrescriptionModal
    const sigY=Math.max(rowY+10, H-55);
    const INK=[28,52,140], INK2=[45,75,170];
    const cx=W-46, cy=sigY+13, R=18;

    sd(INK); pdf.setLineWidth(1.2); pdf.circle(cx,cy,R,"S");
    pdf.setLineWidth(0.4); pdf.circle(cx,cy,R-2.5,"S");

    const drawStar=(sx,sy,sr)=>{
      const pts=[];
      for(let si=0;si<5;si++){
        const ao=(si*4*Math.PI)/5-Math.PI/2, ai=ao+(2*Math.PI)/5;
        pts.push({x:sx+sr*Math.cos(ao),y:sy+sr*Math.sin(ao)});
        pts.push({x:sx+sr*0.4*Math.cos(ai),y:sy+sr*0.4*Math.sin(ai)});
      }
      pdf.setLineWidth(0.3); sd(INK); sf(INK);
      pdf.lines(pts.slice(1).map((pt,i)=>[pt.x-pts[i].x,pt.y-pts[i].y]),pts[0].x,pts[0].y,[1,1],"FD",true);
    };
    drawStar(cx-R+3.5,cy+1,2.2);
    drawStar(cx+R-3.5,cy+1,2.2);

    // doctor name curved at top — IDENTICAL
    const docShort=(doc.name||"Doctor").toUpperCase();
    sd(INK); st(INK); pdf.setFont("helvetica","bold"); pdf.setFontSize(5.8);
    const topSpan=Math.min(docShort.length*0.19,1.3);
    const topStart=-Math.PI/2-topSpan/2;
    for(let ti=0;ti<docShort.length;ti++){
      const ta=topStart+(ti/Math.max(docShort.length-1,1))*topSpan;
      const tx=cx+(R-1.5)*Math.cos(ta), ty=cy+(R-1.5)*Math.sin(ta);
      const trot=((ta+Math.PI/2)*180)/Math.PI;
      pdf.text(docShort[ti],tx,ty,{align:"center",angle:-trot});
    }

    // "PEARLSMILE DENTAL" curved at bottom — IDENTICAL
    pdf.setFontSize(5.5);
    const botStr="PEARLSMILE DENTAL";
    const botSpan=Math.min(botStr.length*0.175,1.4);
    const botStart=Math.PI/2-botSpan/2;
    for(let bi=0;bi<botStr.length;bi++){
      const ba=botStart+(bi/Math.max(botStr.length-1,1))*botSpan;
      const bx=cx+(R-1.5)*Math.cos(ba), by=cy+(R-1.5)*Math.sin(ba);
      const brot=((ba-Math.PI/2)*180)/Math.PI;
      pdf.text(botStr[bi],bx,by,{align:"center",angle:-brot});
    }

    // caduceus rod + wings + snake — IDENTICAL line by line
    sd(INK); pdf.setLineWidth(0.8); pdf.line(cx,cy-8,cx,cy+7);
    pdf.setLineWidth(0.5);
    pdf.line(cx,cy-7.5,cx-4,cy-9.5); pdf.line(cx-4,cy-9.5,cx-6,cy-8); pdf.line(cx-6,cy-8,cx-3,cy-6.5);
    pdf.line(cx,cy-7.5,cx+4,cy-9.5); pdf.line(cx+4,cy-9.5,cx+6,cy-8); pdf.line(cx+6,cy-8,cx+3,cy-6.5);
    sf(INK); pdf.circle(cx,cy-8.2,1,"F");
    pdf.setLineWidth(0.6);
    pdf.lines([[2,-2],[2,-2],[0,-2]],cx-3,cy+5,[1,1],"S");
    pdf.lines([[-2,-2],[-2,-2],[0,-2]],cx+3,cy+1,[1,1],"S");
    pdf.lines([[2,-2],[2,-2]],cx-3,cy-3,[1,1],"S");
    pdf.lines([[-2,-2],[-2,-2],[0,-2]],cx+3,cy+5,[1,1],"S");
    pdf.lines([[2,-2],[2,-2],[0,-2]],cx-3,cy+1,[1,1],"S");

    // "Reg." and "Authorised Signatory" — IDENTICAL
    st(INK); pdf.setFont("helvetica","normal"); pdf.setFontSize(4.5);
    pdf.text("Reg. "+(doc.reg||"—"), cx, cy+R-5.5, { align:"center" });
    st(INK2); pdf.setFont("helvetica","normal"); pdf.setFontSize(6.5);
    pdf.text("Authorised Signatory", cx, cy+R+4, { align:"center" });

    // invoice ref + date below stamp — same as "Rx No." in prescription
    st(GRAY); pdf.setFontSize(7); pdf.setFont("helvetica","normal");
    pdf.text("Invoice: "+(inv.invoiceNumber||"—"), 14, sigY+30);
    pdf.text("Date: "+todayFmt, W-14, sigY+30, { align:"right" });

    // ── Footer — IDENTICAL to PrescriptionModal ───────────────
    sf(NAVY); pdf.rect(3.5,H-21,W-7,17.5,"F");
    sf(BLUE); pdf.rect(3.5,H-7,W-7,3.5,"F");
    st(WHITE); pdf.setFont("helvetica","bold"); pdf.setFontSize(7.5);
    pdf.text("PearlSmile Dental Hospital", 10, H-14.5);
    st(LBLUE); pdf.setFont("helvetica","normal"); pdf.setFontSize(7);
    pdf.text("+91 87936 08083", 10, H-9.5);
    pdf.text("care@pearlsmiledental.in", W/2, H-9.5, { align:"center" });
    pdf.text("12, Dental Plaza, MG Road, Pune - 411001", W-10, H-9.5, { align:"right" });
    st(LBLUE2); pdf.setFontSize(6); pdf.setFont("helvetica","italic");
    pdf.text("This is a computer-generated invoice from PearlSmile Dental Hospital. Valid only with authorised doctor details.", W/2, H-5.5, { align:"center" });

    // ── Output — IDENTICAL to PrescriptionModal ───────────────
    const blob  = pdf.output("blob");
    const url   = URL.createObjectURL(blob);
    const name  = "Invoice_"+(inv.invoiceNumber||"INV")+"_"+(inv.patientName||"Patient").replace(/\s+/g,"_")+".pdf";

    let rawMob = (inv.patientPhone||"").replace(/[\s\-\(\)\+]/g,"");
    if(!rawMob.startsWith("91") && rawMob.length===10) rawMob="91"+rawMob;

    setPdfBlob(blob);
    setPdfUrl(url);
    setFileName(name);
    // native share check — IDENTICAL to PrescriptionModal
    const testFile = new File([blob], name, { type:"application/pdf" });
    if(navigator.share && navigator.canShare && navigator.canShare({ files:[testFile] })){
      setCanNativeShare(true);
    }
    setLoading(false);
  };

  // ── button handlers — IDENTICAL to PrescriptionModal ─────
  const openFullPreview = () => { if(pdfUrl) window.open(pdfUrl,"_blank"); };

  const nativeShare = async () => {
    if(!pdfBlob) return;
    const file = new File([pdfBlob], fileName, { type:"application/pdf" });
    if(navigator.share && navigator.canShare && navigator.canShare({ files:[file] })){
      navigator.share({ title:"Invoice — PearlSmile Dental Hospital", text:"", files:[file] })
        .then(()=>{ showNotify("Shared!","Invoice shared successfully."); onClose(); })
        .catch(err=>{ if(err.name!=="AbortError") showNotify("Share Failed",err.message,true); });
    } else {
      showNotify("Not Supported","Native share not supported on this device/browser.",true);
    }
  };

  // ── Modal JSX — PIXEL-PERFECT copy of PrescriptionModal ──
  return (
    <div
      className="rx-share-overlay open"
      onClick={(e)=>{ if(e.target===e.currentTarget) onClose(); }}
    >
      <div style={{ background:"#fff", borderRadius:20, width:"100%", maxWidth:540,
        boxShadow:"0 24px 80px rgba(0,0,0,0.45)", overflow:"hidden",
        display:"flex", flexDirection:"column", maxHeight:"92vh" }}>

        {/* Header — identical gradient + layout */}
        <div style={{ background:"linear-gradient(135deg,#0a1628,#1a3a6b)", padding:"18px 22px",
          display:"flex", alignItems:"center", justifyContent:"space-between" }}>
          <div style={{ display:"flex", alignItems:"center", gap:10 }}>
            <span style={{ fontSize:22 }}>📄</span>
            <div>
              <div style={{ color:"#fff", fontWeight:600, fontSize:15, fontFamily:"DM Sans,sans-serif" }}>
                Invoice Ready
              </div>
              <div style={{ color:"rgba(255,255,255,0.55)", fontSize:12, fontFamily:"DM Sans,sans-serif" }}>
                {inv.patientName} &middot; {inv.invoiceNumber}
              </div>
            </div>
          </div>
          <button onClick={onClose}
            style={{ background:"rgba(255,255,255,0.12)", border:"none", color:"#fff",
              width:32, height:32, borderRadius:"50%", fontSize:17, cursor:"pointer",
              display:"flex", alignItems:"center", justifyContent:"center" }}>
            ✕
          </button>
        </div>

        {/* PDF preview — identical */}
        <div style={{ flex:1, overflow:"hidden", background:"#f0eeeb", minHeight:340, position:"relative" }}>
          {loading && (
            <div style={{ position:"absolute", inset:0, display:"flex", flexDirection:"column",
              alignItems:"center", justifyContent:"center", background:"#f0eeeb", gap:10 }}>
              <div style={{ width:36, height:36, border:"3px solid #0d7377",
                borderTopColor:"transparent", borderRadius:"50%",
                animation:"spin 0.8s linear infinite" }} />
              <div style={{ fontSize:13, color:"#5a5550", fontFamily:"DM Sans,sans-serif" }}>
                Generating PDF…
              </div>
            </div>
          )}
          {pdfUrl && (
            <iframe title="invoice-preview" src={pdfUrl}
              style={{ width:"100%", height:420, border:"none" }} />
          )}
        </div>

        {/* Action buttons — IDENTICAL to PrescriptionModal */}
        <div style={{ padding:"16px 20px", display:"flex", flexDirection:"column", gap:10, background:"#fff" }}>
          <div style={{ display:"flex", gap:8 }}>
            <button onClick={openFullPreview}
              onMouseOver={(e)=>e.currentTarget.style.background="#e5e0d8"}
              onMouseOut={(e) =>e.currentTarget.style.background="#f0eeeb"}
              style={{ flex:1, background:"#f0eeeb", color:"#0a1628", border:"1.5px solid #ddd9d3",
                borderRadius:10, padding:10, fontSize:13, fontWeight:500, cursor:"pointer",
                fontFamily:"DM Sans,sans-serif", transition:"background 0.2s" }}>
              🔍 Open Full PDF
            </button>
            {canNativeShare && (
              <button onClick={nativeShare}
                onMouseOver={(e)=>e.currentTarget.style.background="#e5e0d8"}
                onMouseOut={(e) =>e.currentTarget.style.background="#f0eeeb"}
                style={{ flex:1, background:"#f0eeeb", color:"#0a1628", border:"1.5px solid #ddd9d3",
                  borderRadius:10, padding:10, fontSize:13, fontWeight:500, cursor:"pointer",
                  fontFamily:"DM Sans,sans-serif", transition:"background 0.2s" }}>
                📤 Share (Device)
              </button>
            )}
          </div>
          <p style={{ fontSize:11, color:"#9a9590", textAlign:"center", margin:0,
            fontFamily:"DM Sans,sans-serif", lineHeight:1.5 }}>
            On mobile: tap "Share (Device)" to send directly via WhatsApp.<br />
            On desktop: use "Open Full PDF" to view, then share manually.
          </p>
        </div>
      </div>

      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );
}

// ── Patient Picker Modal ──────────────────────────────────────
function PatientPickerModal({ patients, onSelect, onClose }) {
  const [q, setQ] = useState("");
  const list = patients.filter((p)=>
    (p.name||"").toLowerCase().includes(q.toLowerCase())||(p.mobile||"").includes(q)
  );
  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.5)", zIndex:9000,
      display:"flex", alignItems:"center", justifyContent:"center", padding:"16px" }}>
      <div style={{ background:"#fff", borderRadius:"12px", width:"100%", maxWidth:"480px",
        maxHeight:"80vh", display:"flex", flexDirection:"column",
        boxShadow:"0 8px 40px rgba(0,0,0,0.2)" }}>
        <div style={{ padding:"16px 20px", borderBottom:"1px solid #e5e7eb",
          display:"flex", justifyContent:"space-between", alignItems:"center" }}>
          <span style={{ fontWeight:700, fontSize:"15px", color:"#1e293b" }}>Select Patient</span>
          <button onClick={onClose} style={{ background:"none", border:"none",
            fontSize:"20px", cursor:"pointer", color:"#94a3b8", lineHeight:1 }}>x</button>
        </div>
        <div style={{ padding:"12px 20px", borderBottom:"1px solid #f1f5f9" }}>
          <input value={q} onChange={(e)=>setQ(e.target.value)}
            placeholder="Search by name or phone..." style={INPUT} autoFocus />
        </div>
        <div style={{ overflowY:"auto", flex:1 }}>
          {list.length===0 ? (
            <div style={{ padding:"30px", textAlign:"center", color:"#94a3b8", fontSize:"13px" }}>
              No patients found
            </div>
          ) : list.map((p)=>(
            <div key={p._id} onClick={()=>onSelect(p)}
              style={{ padding:"12px 20px", borderBottom:"1px solid #f8fafc",
                cursor:"pointer", display:"flex", justifyContent:"space-between", alignItems:"center" }}
              onMouseEnter={(e)=>e.currentTarget.style.background="#f0f9ff"}
              onMouseLeave={(e)=>e.currentTarget.style.background="#fff"}>
              <div>
                <div style={{ fontWeight:600, fontSize:"14px", color:"#1e293b" }}>{p.name}</div>
                <div style={{ fontSize:"12px", color:"#64748b", marginTop:"2px" }}>
                  {p.mobile}{p.age?" | Age: "+p.age:""}{p.gender?" | "+p.gender:""}
                </div>
              </div>
              <div style={{ fontSize:"11px", color:"#94a3b8" }}>{(p.visits||[]).length} visits</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// ── Invoice Form ──────────────────────────────────────────────
function InvoiceForm({ patients, doctor, invoice, onSave, onCancel, showNotify }) {
  const isEdit = !!invoice;
  const [showPicker, setShowPicker] = useState(false);
  const [saving,     setSaving]     = useState(false);

  const blank = {
    patientId:"", patientName:"", patientPhone:"", patientAge:"", patientGender:"",
    doctorName:(doctor&&doctor.name)||"", doctorId:(doctor&&doctor.doctorId)||"",
    invoiceDate:todayISO(), discountType:"flat", discountValue:"0", gstPercent:"0",
    paymentStatus:"unpaid", paymentMethod:"cash", amountPaid:"0",
    paymentDate:todayISO(), receiptNumber:"", upiId:"",
    insuranceProvider:"", insuranceClaimNo:"", insuranceStatus:"", notes:"",
  };
  const [form,  setForm]  = useState(blank);
  const [items, setItems] = useState([{ treatment:"", quantity:"1", rate:"", amount:"0" }]);

  useEffect(()=>{
    if(invoice){
      setForm({
        patientId:         invoice.patientId         ||"",
        patientName:       invoice.patientName       ||"",
        patientPhone:      invoice.patientPhone      ||"",
        patientAge:        invoice.patientAge        ||"",
        patientGender:     invoice.patientGender     ||"",
        doctorName:        invoice.doctorName        ||(doctor&&doctor.name)||"",
        doctorId:          invoice.doctorId          ||(doctor&&doctor.doctorId)||"",
        invoiceDate:       invoice.invoiceDate       ||todayISO(),
        discountType:      invoice.discountType      ||"flat",
        discountValue:     String(invoice.discountValue ||0),
        gstPercent:        String(invoice.gstPercent    ||0),
        paymentStatus:     invoice.paymentStatus     ||"unpaid",
        paymentMethod:     invoice.paymentMethod     ||"cash",
        amountPaid:        String(invoice.amountPaid ||0),
        paymentDate:       invoice.paymentDate       ||todayISO(),
        receiptNumber:     invoice.receiptNumber     ||"",
        upiId:             invoice.upiId             ||"",
        insuranceProvider: invoice.insuranceProvider ||"",
        insuranceClaimNo:  invoice.insuranceClaimNo  ||"",
        insuranceStatus:   invoice.insuranceStatus   ||"",
        notes:             invoice.notes             ||"",
      });
      setItems((invoice.items||[]).map((i)=>({
        treatment:String(i.treatment||""), quantity:String(i.quantity||1),
        rate:String(i.rate||""), amount:String(i.amount||0),
      })));
    }
  },[invoice,doctor]);

  const setF=(k,v)=>setForm((f)=>({...f,[k]:v}));

  const pickPatient=(p)=>{
    setForm((f)=>({...f, patientId:p._id, patientName:p.name,
      patientPhone:p.mobile||"", patientAge:p.age||"", patientGender:p.gender||""}));
    setShowPicker(false);
  };

  const updateItem=(idx,key,val)=>{
    setItems((prev)=>{
      const arr=prev.map((x)=>({...x}));
      arr[idx][key]=val;
      if(key==="quantity"||key==="rate"){
        const q=parseFloat(key==="quantity"?val:arr[idx].quantity)||0;
        const r=parseFloat(key==="rate"    ?val:arr[idx].rate    )||0;
        arr[idx].amount=String((q*r).toFixed(2));
      }
      return arr;
    });
  };

  const addItem   =()=>setItems((p)=>[...p,{treatment:"",quantity:"1",rate:"",amount:"0"}]);
  const removeItem=(idx)=>setItems((p)=>p.filter((_,i)=>i!==idx));

  const {subtotal,discountAmount,gstAmount,totalAmount}=
    calcTotals(items,form.discountType,form.discountValue,form.gstPercent);
  const amountDue=Math.max(0,totalAmount-(parseFloat(form.amountPaid)||0));

  const handleSave=async()=>{
    if(!form.patientId){ showNotify("Error","Please select a patient.",true); return; }
    if(items.some((i)=>!i.treatment||!i.rate)){
      showNotify("Error","Fill treatment and rate for all items.",true); return;
    }
    setSaving(true);
    try{
      const paid=parseFloat(form.amountPaid)||0;
      const payload={...form,
        discountValue:parseFloat(form.discountValue)||0,
        gstPercent:   parseFloat(form.gstPercent)||0,
        amountPaid:   paid,
        items:items.map((i)=>({
          treatment:i.treatment, quantity:parseFloat(i.quantity)||1,
          rate:parseFloat(i.rate)||0, amount:parseFloat(i.amount)||0,
        })),
        subtotal,discountAmount,gstAmount,totalAmount,amountDue,
        paymentStatus: paid>=totalAmount&&totalAmount>0?"paid": paid>0?"partial":"unpaid",
      };
      if(isEdit){ await api.put("/billing/"+invoice._id,payload); showNotify("Saved","Invoice updated."); }
      else      { await api.post("/billing",payload);             showNotify("Created","Invoice created."); }
      onSave();
    }catch(err){ showNotify("Error",err.message,true); }
    setSaving(false);
  };

  return (
    <div>
      {showPicker&&<PatientPickerModal patients={patients} onSelect={pickPatient} onClose={()=>setShowPicker(false)} />}

      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center",
        marginBottom:"20px", flexWrap:"wrap", gap:"10px" }}>
        <h3 style={{ margin:0, color:"#1e293b", fontSize:"17px" }}>
          {isEdit?"Edit Invoice":"New Invoice"}
        </h3>
        <div style={{ display:"flex", gap:"8px" }}>
          <button onClick={onCancel} style={GHOST}>Cancel</button>
          <button onClick={handleSave} disabled={saving}
            style={{...BTN,opacity:saving?0.7:1}}>
            {saving?"Saving...":isEdit?"Update Invoice":"Create Invoice"}
          </button>
        </div>
      </div>

      <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(300px,1fr))", gap:"16px" }}>
        <div style={CARD}>
          <div style={{ fontWeight:700,fontSize:"13px",color:"#1e40af",marginBottom:"12px",textTransform:"uppercase",letterSpacing:"0.5px" }}>Patient Details</div>
          <button onClick={()=>setShowPicker(true)}
            style={{...GHOST,width:"100%",marginBottom:"12px",textAlign:"left"}}>
            {form.patientName?form.patientName+" — "+form.patientPhone:"Select Patient from Profile..."}
          </button>
          {form.patientName&&(
            <div style={{ background:"#f0f9ff",border:"1px solid #bae6fd",borderRadius:"7px",padding:"10px 12px",fontSize:"12px",color:"#0369a1" }}>
              <strong>{form.patientName}</strong> &nbsp;|&nbsp; {form.patientPhone}
              {form.patientAge   ?" | Age: "+form.patientAge:""}
              {form.patientGender?" | "+form.patientGender:""}
            </div>
          )}
        </div>
        <div style={CARD}>
          <div style={{ fontWeight:700,fontSize:"13px",color:"#1e40af",marginBottom:"12px",textTransform:"uppercase",letterSpacing:"0.5px" }}>Invoice Details</div>
          <div style={{ display:"grid",gridTemplateColumns:"1fr 1fr",gap:"10px" }}>
            <div><label style={LABEL}>Invoice Date</label>
              <input type="date" value={form.invoiceDate} onChange={(e)=>setF("invoiceDate",e.target.value)} style={INPUT}/></div>
            <div><label style={LABEL}>Doctor Name</label>
              <input value={form.doctorName} onChange={(e)=>setF("doctorName",e.target.value)} style={INPUT}/></div>
          </div>
        </div>
      </div>

      <div style={{...CARD,marginTop:"16px"}}>
        <div style={{ fontWeight:700,fontSize:"13px",color:"#1e40af",marginBottom:"14px",textTransform:"uppercase",letterSpacing:"0.5px" }}>Treatments / Services</div>
        <div style={{ display:"grid",gridTemplateColumns:"3fr 80px 100px 100px 36px",gap:"8px",marginBottom:"6px" }}>
          {["Treatment","Qty","Rate (Rs.)","Amount",""].map((h,i)=>(
            <div key={i} style={{ fontSize:"11px",color:"#94a3b8",fontWeight:600,textTransform:"uppercase" }}>{h}</div>
          ))}
        </div>
        {items.map((item,idx)=>(
          <div key={idx} style={{ display:"grid",gridTemplateColumns:"3fr 80px 100px 100px 36px",gap:"8px",marginBottom:"8px",alignItems:"center" }}>
            <div>
              <input list={"tx-"+idx} value={item.treatment}
                onChange={(e)=>updateItem(idx,"treatment",e.target.value)}
                placeholder="Type or select..." style={INPUT}/>
              <datalist id={"tx-"+idx}>{DENTAL_TREATMENTS.map((t)=><option key={t} value={t}/>)}</datalist>
            </div>
            <input type="number" min="1" value={item.quantity} onChange={(e)=>updateItem(idx,"quantity",e.target.value)} style={INPUT}/>
            <input type="number" min="0" value={item.rate}     onChange={(e)=>updateItem(idx,"rate",    e.target.value)} placeholder="0" style={INPUT}/>
            <input readOnly value={fmtMoney(item.amount)} style={{...INPUT,background:"#f8fafc",fontWeight:600}}/>
            <button onClick={()=>removeItem(idx)} disabled={items.length===1}
              style={{ padding:"6px",borderRadius:"6px",background:"#fef2f2",
                border:"1px solid #fca5a5",color:"#dc2626",
                cursor:items.length===1?"default":"pointer",fontSize:"13px",fontWeight:700 }}>
              x
            </button>
          </div>
        ))}
        <button onClick={addItem} style={{...GHOST,marginTop:"6px",fontSize:"12px"}}>+ Add Treatment</button>
      </div>

      <div style={{ display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(280px,1fr))",gap:"16px",marginTop:"16px" }}>
        <div style={CARD}>
          <div style={{ fontWeight:700,fontSize:"13px",color:"#1e40af",marginBottom:"12px",textTransform:"uppercase",letterSpacing:"0.5px" }}>Discount and Tax</div>
          <div style={{ display:"grid",gridTemplateColumns:"1fr 1fr",gap:"10px" }}>
            <div><label style={LABEL}>Discount Type</label>
              <select value={form.discountType} onChange={(e)=>setF("discountType",e.target.value)} style={INPUT}>
                <option value="flat">Flat (Rs.)</option>
                <option value="percent">Percentage (%)</option>
              </select></div>
            <div><label style={LABEL}>Discount Value</label>
              <input type="number" min="0" value={form.discountValue} onChange={(e)=>setF("discountValue",e.target.value)} style={INPUT}/></div>
            <div><label style={LABEL}>GST (%)</label>
              <input type="number" min="0" max="100" value={form.gstPercent} onChange={(e)=>setF("gstPercent",e.target.value)} style={INPUT}/></div>
          </div>
        </div>
        <div style={{...CARD,background:"#f8fafc"}}>
          <div style={{ fontWeight:700,fontSize:"13px",color:"#1e40af",marginBottom:"12px",textTransform:"uppercase",letterSpacing:"0.5px" }}>Summary</div>
          {[["Subtotal",fmtMoney(subtotal)],["Discount","- "+fmtMoney(discountAmount)],["GST","+ "+fmtMoney(gstAmount)]].map(([k,v])=>(
            <div key={k} style={{ display:"flex",justifyContent:"space-between",fontSize:"13px",color:"#475569",marginBottom:"6px" }}>
              <span>{k}</span><span>{v}</span>
            </div>
          ))}
          <div style={{ display:"flex",justifyContent:"space-between",fontSize:"16px",fontWeight:800,color:"#1e293b",borderTop:"2px solid #e5e7eb",paddingTop:"8px",marginTop:"6px" }}>
            <span>Total</span><span style={{ color:"#1e40af" }}>{fmtMoney(totalAmount)}</span>
          </div>
        </div>
      </div>

      <div style={{...CARD,marginTop:"16px"}}>
        <div style={{ fontWeight:700,fontSize:"13px",color:"#1e40af",marginBottom:"12px",textTransform:"uppercase",letterSpacing:"0.5px" }}>Payment Details</div>
        <div style={{ display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(160px,1fr))",gap:"10px" }}>
          <div><label style={LABEL}>Payment Method</label>
            <select value={form.paymentMethod} onChange={(e)=>setF("paymentMethod",e.target.value)} style={INPUT}>
              {PAYMENT_METHODS.map((m)=><option key={m.value} value={m.value}>{m.label}</option>)}
            </select></div>
          <div><label style={LABEL}>Amount Paid (Rs.)</label>
            <input type="number" min="0" value={form.amountPaid} onChange={(e)=>setF("amountPaid",e.target.value)} style={INPUT}/></div>
          <div><label style={LABEL}>Amount Due</label>
            <input readOnly value={fmtMoney(amountDue)}
              style={{...INPUT,background:"#fef2f2",fontWeight:700,color:amountDue>0?"#dc2626":"#16a34a"}}/></div>
          <div><label style={LABEL}>Payment Date</label>
            <input type="date" value={form.paymentDate} onChange={(e)=>setF("paymentDate",e.target.value)} style={INPUT}/></div>
          <div><label style={LABEL}>Receipt No.</label>
            <input value={form.receiptNumber} onChange={(e)=>setF("receiptNumber",e.target.value)} placeholder="e.g. RCP-001" style={INPUT}/></div>
          {form.paymentMethod==="upi"&&(
            <div><label style={LABEL}>UPI ID</label>
              <input value={form.upiId} onChange={(e)=>setF("upiId",e.target.value)} placeholder="name@upi" style={INPUT}/></div>
          )}
        </div>
      </div>

      <div style={{...CARD,marginTop:"16px"}}>
        <div style={{ fontWeight:700,fontSize:"13px",color:"#1e40af",marginBottom:"12px",textTransform:"uppercase",letterSpacing:"0.5px" }}>Insurance (Optional)</div>
        <div style={{ display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(180px,1fr))",gap:"10px" }}>
          <div><label style={LABEL}>Insurance Provider</label>
            <input value={form.insuranceProvider} onChange={(e)=>setF("insuranceProvider",e.target.value)} placeholder="Provider name" style={INPUT}/></div>
          <div><label style={LABEL}>Claim Number</label>
            <input value={form.insuranceClaimNo} onChange={(e)=>setF("insuranceClaimNo",e.target.value)} placeholder="Claim no." style={INPUT}/></div>
          <div><label style={LABEL}>Claim Status</label>
            <select value={form.insuranceStatus} onChange={(e)=>setF("insuranceStatus",e.target.value)} style={INPUT}>
              <option value="">Not Applicable</option>
              <option value="pending">Pending</option>
              <option value="approved">Approved</option>
              <option value="rejected">Rejected</option>
            </select></div>
        </div>
      </div>

      <div style={{...CARD,marginTop:"16px"}}>
        <label style={LABEL}>Notes / Remarks</label>
        <textarea value={form.notes} onChange={(e)=>setF("notes",e.target.value)}
          placeholder="Any additional notes..." rows={3}
          style={{...INPUT,resize:"vertical"}}/>
      </div>

      <div style={{ display:"flex",justifyContent:"flex-end",gap:"10px",marginTop:"20px" }}>
        <button onClick={onCancel} style={GHOST}>Cancel</button>
        <button onClick={handleSave} disabled={saving}
          style={{...BTN,opacity:saving?0.7:1}}>
          {saving?"Saving...":isEdit?"Update Invoice":"Create Invoice"}
        </button>
      </div>
    </div>
  );
}

// ── Invoice List Row ──────────────────────────────────────────
function InvoiceRow({ inv, onEdit, onDelete, onShare }) {
  const cfg=STATUS_CFG[inv.paymentStatus]||STATUS_CFG.unpaid;
  return (
    <div style={{...CARD,marginBottom:"10px",borderLeft:"4px solid "+cfg.color,
      display:"flex",flexWrap:"wrap",gap:"12px",alignItems:"center"}}>
      <div style={{ flex:"0 0 110px" }}>
        <div style={{ fontSize:"12px",color:"#94a3b8",fontWeight:600 }}>Invoice No.</div>
        <div style={{ fontWeight:700,fontSize:"14px",color:"#1e40af" }}>{inv.invoiceNumber}</div>
        <div style={{ fontSize:"11px",color:"#94a3b8",marginTop:"2px" }}>{friendlyDate(inv.invoiceDate)}</div>
      </div>
      <div style={{ flex:"1 1 160px" }}>
        <div style={{ fontWeight:700,fontSize:"14px",color:"#1e293b" }}>{inv.patientName}</div>
        <div style={{ fontSize:"12px",color:"#64748b" }}>{inv.patientPhone}</div>
        <div style={{ fontSize:"11px",color:"#94a3b8",marginTop:"2px" }}>Dr. {inv.doctorName}</div>
      </div>
      <div style={{ flex:"1 1 180px" }}>
        <div style={{ fontSize:"11px",color:"#94a3b8",fontWeight:600 }}>Services</div>
        <div style={{ fontSize:"12px",color:"#475569" }}>
          {(inv.items||[]).map((i)=>i.treatment).join(", ").slice(0,60)||"--"}
        </div>
      </div>
      <div style={{ flex:"0 0 100px",textAlign:"right" }}>
        <div style={{ fontWeight:800,fontSize:"15px",color:"#1e293b" }}>{fmtMoney(inv.totalAmount)}</div>
        {(inv.amountDue||0)>0&&(
          <div style={{ fontSize:"11px",color:"#dc2626",fontWeight:600 }}>Due: {fmtMoney(inv.amountDue)}</div>
        )}
      </div>
      <div style={{ flex:"0 0 auto" }}>
        <span style={{ padding:"3px 10px",borderRadius:"12px",background:cfg.bg,
          color:cfg.color,border:"1px solid "+cfg.color,fontSize:"11px",fontWeight:700 }}>
          {cfg.label}
        </span>
      </div>
      <div style={{ display:"flex",gap:"6px",flex:"0 0 auto",flexWrap:"wrap" }}>
        {/* Same green WhatsApp button — triggers InvoiceShareModal like Send Prescription */}
        <button onClick={()=>onShare(inv)}
          style={{ padding:"5px 12px",borderRadius:"8px",background:"#dcfce7",
            color:"#16a34a",border:"1px solid #16a34a",fontSize:"12px",fontWeight:700,cursor:"pointer" }}
          title={"Send invoice PDF to "+inv.patientName+" via WhatsApp"}>
          Send on WhatsApp
        </button>
        <button onClick={()=>onEdit(inv)}
          style={{...GHOST,padding:"5px 12px",fontSize:"12px"}}>
          Edit
        </button>
        <button onClick={()=>onDelete(inv._id)}
          style={{ padding:"5px 10px",borderRadius:"8px",background:"#fef2f2",
            color:"#dc2626",border:"1px solid #fca5a5",fontSize:"12px",fontWeight:600,cursor:"pointer" }}>
          Del
        </button>
      </div>
    </div>
  );
}

// ── Summary Cards ─────────────────────────────────────────────
function SummaryCards({ summary }) {
  if(!summary) return null;
  const cards=[
    { label:"Total Revenue",    value:fmtMoney(summary.totalRevenue),    color:"#16a34a" },
    { label:"This Month",       value:fmtMoney(summary.monthlyRevenue),  color:"#2563eb" },
    { label:"This Week",        value:fmtMoney(summary.weeklyRevenue),   color:"#7c3aed" },
    { label:"Today",            value:fmtMoney(summary.dailyRevenue),    color:"#0891b2" },
    { label:"Outstanding Dues", value:fmtMoney(summary.totalOutstanding),color:"#dc2626" },
    { label:"Unpaid Invoices",  value:summary.unpaidCount,               color:"#dc2626" },
    { label:"Partial",          value:summary.partialCount,              color:"#d97706" },
    { label:"Paid",             value:summary.paidCount,                 color:"#16a34a" },
  ];
  return (
    <div style={{ display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(130px,1fr))",gap:"10px",marginBottom:"24px" }}>
      {cards.map((c)=>(
        <div key={c.label} style={{ background:"#fff",border:"1px solid #e5e7eb",
          borderTop:"3px solid "+c.color,borderRadius:"8px",padding:"12px",
          textAlign:"center",boxShadow:"0 1px 3px rgba(0,0,0,0.05)" }}>
          <div style={{ fontSize:"18px",fontWeight:800,color:c.color }}>{c.value}</div>
          <div style={{ fontSize:"10px",color:"#94a3b8",fontWeight:600,marginTop:"2px" }}>{c.label}</div>
        </div>
      ))}
    </div>
  );
}

// ── Main BillingTab ───────────────────────────────────────────
export default function BillingTab({ showNotify, doctor }) {
  const [view,          setView]          = useState("list");
  const [invoices,      setInvoices]      = useState([]);
  const [patients,      setPatients]      = useState([]);
  const [summary,       setSummary]       = useState(null);
  const [loading,       setLoading]       = useState(true);
  const [editing,       setEditing]       = useState(null);
  const [sharingInv,    setSharingInv]    = useState(null);
  const [search,        setSearch]        = useState("");
  const [filterStatus,  setFilterStatus]  = useState("all");
  const [filterPatient, setFilterPatient] = useState("");

  const load = useCallback(async()=>{
    setLoading(true);
    try{
      const [inv,pat,sum]=await Promise.all([
        api.get("/billing"),
        api.get("/billing/patients"),
        api.get("/billing/summary"),
      ]);
      setInvoices(Array.isArray(inv)?inv:[]);
      setPatients(Array.isArray(pat)?pat:[]);
      setSummary(sum);
    }catch(err){ showNotify("Error",err.message,true); }
    setLoading(false);
  },[showNotify]);

  useEffect(()=>{ load(); },[load]);

  const handleDelete=async(id)=>{
    if(!window.confirm("Delete this invoice permanently?")) return;
    try{
      await api.delete("/billing/"+id);
      setInvoices((p)=>p.filter((i)=>i._id!==id));
      showNotify("Deleted","Invoice removed.");
      load();
    }catch(err){ showNotify("Error",err.message,true); }
  };

  const handleEdit =(inv)=>{ setEditing(inv); setView("edit"); };
  const handleNew  =()=>   { setEditing(null); setView("new"); };
  const handleSaved=()=>   { setView("list"); setEditing(null); load(); };

  const filtered=invoices.filter((inv)=>{
    const q=search.toLowerCase();
    return(
      (!q||(inv.patientName||"").toLowerCase().includes(q)||(inv.invoiceNumber||"").toLowerCase().includes(q)||(inv.patientPhone||"").includes(q))&&
      (filterStatus==="all"||inv.paymentStatus===filterStatus)&&
      (!filterPatient||inv.patientId===filterPatient)
    );
  });

  const patientTotals={};
  invoices.forEach((inv)=>{
    if(!patientTotals[inv.patientId]) patientTotals[inv.patientId]={name:inv.patientName,total:0,count:0};
    patientTotals[inv.patientId].total+=inv.totalAmount||0;
    patientTotals[inv.patientId].count+=1;
  });

  if(view==="new"||view==="edit"){
    return(
      <div style={{ padding:"0 0 40px" }}>
        <InvoiceForm patients={patients} doctor={doctor}
          invoice={view==="edit"?editing:null}
          onSave={handleSaved} onCancel={()=>setView("list")} showNotify={showNotify}/>
      </div>
    );
  }

  return(
    <div style={{ padding:"0 0 40px" }}>

      {/* InvoiceShareModal — appears exactly like PrescriptionModal */}
      {sharingInv&&(
        <InvoiceShareModal
          inv={sharingInv}
          onClose={()=>setSharingInv(null)}
          showNotify={showNotify}
        />
      )}

      <SummaryCards summary={summary}/>

      <div style={{ display:"flex",flexWrap:"wrap",gap:"10px",marginBottom:"16px",alignItems:"center" }}>
        <input value={search} onChange={(e)=>setSearch(e.target.value)}
          placeholder="Search by patient, invoice number, phone..."
          style={{...INPUT,flex:"1 1 220px"}}/>
        <select value={filterStatus} onChange={(e)=>setFilterStatus(e.target.value)}
          style={{...INPUT,width:"auto"}}>
          <option value="all">All Statuses</option>
          {Object.keys(STATUS_CFG).map((k)=><option key={k} value={k}>{STATUS_CFG[k].label}</option>)}
        </select>
        <select value={filterPatient} onChange={(e)=>setFilterPatient(e.target.value)}
          style={{...INPUT,width:"auto",maxWidth:"200px"}}>
          <option value="">All Patients</option>
          {patients.map((p)=><option key={p._id} value={p._id}>{p.name}</option>)}
        </select>
        <button onClick={load}      style={GHOST}>Refresh</button>
        <button onClick={handleNew} style={BTN}>+ New Invoice</button>
      </div>

      {loading?(
        <div style={{ textAlign:"center",padding:"40px",color:"#94a3b8",fontSize:"15px" }}>Loading invoices...</div>
      ):filtered.length===0?(
        <div style={{ textAlign:"center",padding:"40px",background:"#f8fafc",borderRadius:"10px",
          color:"#94a3b8",fontSize:"14px",border:"1px dashed #e2e8f0" }}>
          No invoices found. Click "+ New Invoice" to create one.
        </div>
      ):(
        <>
          <div style={{ fontSize:"12px",color:"#94a3b8",marginBottom:"10px",fontWeight:600 }}>
            Showing {filtered.length} invoice(s)
          </div>
          {filtered.map((inv)=>(
            <InvoiceRow key={inv._id} inv={inv}
              onEdit={handleEdit} onDelete={handleDelete}
              onShare={(i)=>setSharingInv(i)}/>
          ))}
        </>
      )}

      {Object.keys(patientTotals).length>0&&(
        <div style={{...CARD,marginTop:"28px"}}>
          <div style={{ fontWeight:700,fontSize:"13px",color:"#1e40af",marginBottom:"14px",textTransform:"uppercase",letterSpacing:"0.5px" }}>
            Patient Billing History
          </div>
          <div style={{ display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(200px,1fr))",gap:"10px" }}>
            {Object.entries(patientTotals).sort((a,b)=>b[1].total-a[1].total).map(([pid,data])=>(
              <div key={pid} onClick={()=>setFilterPatient(pid)}
                style={{ background:"#f8fafc",borderRadius:"8px",padding:"10px 14px",
                  cursor:"pointer",border:"1px solid #e5e7eb" }}
                onMouseEnter={(e)=>e.currentTarget.style.borderColor="#2563eb"}
                onMouseLeave={(e)=>e.currentTarget.style.borderColor="#e5e7eb"}>
                <div style={{ fontWeight:600,fontSize:"13px",color:"#1e293b" }}>{data.name}</div>
                <div style={{ fontSize:"12px",color:"#64748b",marginTop:"3px" }}>{data.count} invoice(s)</div>
                <div style={{ fontSize:"14px",fontWeight:800,color:"#1e40af",marginTop:"4px" }}>{fmtMoney(data.total)}</div>
              </div>
            ))}
          </div>
        </div>
      )}

      {summary&&(summary.topServices||[]).length>0&&(
        <div style={{...CARD,marginTop:"16px"}}>
          <div style={{ fontWeight:700,fontSize:"13px",color:"#1e40af",marginBottom:"14px",textTransform:"uppercase",letterSpacing:"0.5px" }}>
            Top Billed Treatments
          </div>
          {summary.topServices.map((s,i)=>{
            const pct=Math.round((s.amount/(summary.topServices[0].amount||1))*100);
            return(
              <div key={i} style={{ marginBottom:"10px" }}>
                <div style={{ display:"flex",justifyContent:"space-between",fontSize:"12px",marginBottom:"4px" }}>
                  <span style={{ color:"#334155",fontWeight:500 }}>{s.name}</span>
                  <span style={{ color:"#1e40af",fontWeight:700 }}>{fmtMoney(s.amount)}</span>
                </div>
                <div style={{ background:"#e5e7eb",borderRadius:"20px",height:"6px" }}>
                  <div style={{ background:"#1e40af",borderRadius:"20px",height:"6px",width:pct+"%" }}/>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
